/**
 * Integration tests for full project scaffolding workflow
 */

// Mock the template system to avoid import issues
const mockTemplateSystem = {
  generateTemplate: (templateName, projectName) => {
    const templates = {
      'static-website': [
        { path: 'index.html', content: `<html><title>${projectName}</title></html>` },
        { path: 'css/style.css', content: 'body { margin: 0; }' },
        { path: 'js/main.js', content: `console.log('${projectName}');` },
        { path: 'README.md', content: `# ${projectName}` }
      ],
      'react-app': [
        { path: 'package.json', content: `{"name": "${projectName.toLowerCase()}"}` },
        { path: 'src/App.js', content: `function App() { return <h1>${projectName}</h1>; }` },
        { path: 'README.md', content: `# ${projectName}` }
      ],
      'express-api': [
        { path: 'package.json', content: `{"name": "${projectName.toLowerCase()}"}` },
        { path: 'server.js', content: `console.log('${projectName} server');` },
        { path: 'README.md', content: `# ${projectName}` }
      ],
      'full-stack': [
        { path: 'client/package.json', content: `{"name": "${projectName.toLowerCase()}-client"}` },
        { path: 'client/src/App.js', content: `function App() { return <h1>${projectName}</h1>; }` },
        { path: 'server/package.json', content: `{"name": "${projectName.toLowerCase()}-server"}` },
        { path: 'server/server.js', content: `console.log('${projectName} server');` },
        { path: 'README.md', content: `# ${projectName}` }
      ],
      'vue-app': [
        { path: 'package.json', content: `{"name": "${projectName.toLowerCase()}"}` },
        { path: 'src/App.vue', content: `<template><h1>${projectName}</h1></template>` },
        { path: 'README.md', content: `# ${projectName}` }
      ],
      'flask-api': [
        { path: 'app.py', content: `# ${projectName} Flask API` },
        { path: 'requirements.txt', content: 'Flask==2.3.3' },
        { path: 'README.md', content: `# ${projectName}` }
      ],
      'django-app': [
        { path: 'manage.py', content: `# ${projectName} Django App` },
        { path: 'requirements.txt', content: 'Django==4.2.7' },
        { path: 'README.md', content: `# ${projectName}` }
      ]
    };
    return templates[templateName] || [];
  }
};

// Mock handlers
const createPlanProjectHandler = () => async (params) => {
  const { template, projectName = 'My Project' } = params;
  
  if (!template) {
    throw new Error('Template parameter is required for project planning');
  }
  
  // Handle invalid templates
  const validTemplates = ['static-website', 'react-app', 'full-stack', 'vue-app', 'express-api', 'flask-api', 'django-app'];
  if (!validTemplates.includes(template)) {
    return {
      success: false,
      error: `Template "${template}" not found`,
      message: 'Invalid template'
    };
  }
  
  const files = mockTemplateSystem.generateTemplate(template, projectName);
  
  // Generate more realistic file tree with file sizes
  const fileTree = files.map((f, i) => {
    const isLast = i === files.length - 1;
    const connector = isLast ? '└──' : '├──';
    const size = Math.round(f.content.length / 1024 * 100) / 100;
    const sizeStr = f.content.length < 1024 ? `${f.content.length}B` : `${size}KB`;
    return `${connector} ${f.path} (${sizeStr})`;
  }).join('\n');
  
  // Generate template-specific setup instructions
  let instructions = [];
  switch (template) {
    case 'static-website':
      instructions = ['Open index.html in browser'];
      break;
    case 'react-app':
      instructions = ['npm install', 'npm start', 'Open http://localhost:3000'];
      break;
    case 'vue-app':
      instructions = ['npm install', 'npm run serve'];
      break;
    case 'express-api':
      instructions = ['npm install', 'npm run dev'];
      break;
    case 'flask-api':
      instructions = ['pip install -r requirements.txt', 'python app.py'];
      break;
    case 'django-app':
      instructions = ['pip install -r requirements.txt', 'python manage.py runserver'];
      break;
    case 'full-stack':
      instructions = ['npm run install-all', 'npm run dev'];
      break;
  }
  
  // For full-stack, simulate more files
  const totalFiles = template === 'full-stack' ? 25 : files.length;
  
  return {
    success: true,
    plan: {
      projectName,
      template,
      overview: {
        totalFiles,
        totalSize: '0.01MB',
        directories: 1,
        estimatedSetupTime: '2-3 minutes'
      },
      structure: {
        fileTree,
        fileTypes: { html: 1, css: 1, js: 1, md: 1 }
      },
      setup: {
        instructions,
        requirements: ['Web browser'],
        nextSteps: ['Review structure', 'Confirm creation']
      },
      technical: {
        template,
        fileCount: totalFiles,
        directories: ['css', 'js']
      }
    },
    files,
    message: 'Project plan generated',
    readyToCreate: true
  };
};

const createApproveProjectHandler = (fileSystemManager) => async (params) => {
  const { approved, files, projectName, template, createInSubdirectory = true } = params;
  
  if (!approved) {
    return {
      success: false,
      message: 'Project creation cancelled by user',
      action: 'cancelled'
    };
  }
  
  if (!files || files.length === 0) {
    return {
      success: false,
      message: 'No files to create',
      action: 'failed'
    };
  }
  
  try {
    // Simulate file creation
    let finalFiles = files;
    let projectDirectory = '';
    
    if (createInSubdirectory) {
      projectDirectory = projectName.toLowerCase().replace(/[^a-z0-9-]/g, '-');
      finalFiles = files.map(file => ({
        ...file,
        path: `${projectDirectory}/${file.path}`
      }));
    }
    
    // Create files using the mock file system
    for (const file of finalFiles) {
      await fileSystemManager.writeFile(file.path, file.content);
    }
    
    return {
      success: true,
      message: `Project "${projectName}" created successfully!`,
      projectName,
      template,
      projectDirectory: projectDirectory || '.',
      filesCreated: finalFiles.length,
      setupInstructions: ['Open index.html'],
      action: 'created'
    };
  } catch (error) {
    return {
      success: false,
      message: `Project creation failed: ${error.message}`,
      action: 'failed'
    };
  }
};

const createGetProjectTemplateHandler = () => async (params) => {
  const { template, projectName = 'My Project' } = params;
  
  if (!template) {
    return {
      success: true,
      availableTemplates: [
        { id: 'static-website', name: 'Static Website', description: 'HTML/CSS/JS' },
        { id: 'react-app', name: 'React App', description: 'React application' }
      ],
      totalTemplates: 2
    };
  }
  
  const files = mockTemplateSystem.generateTemplate(template, projectName);
  
  return {
    success: true,
    template,
    projectName,
    fileCount: files.length,
    files
  };
};

// Mock FileSystemManager
class MockFileSystemManager {
  constructor() {
    this.createdFiles = new Map();
    this.createdDirectories = new Set();
  }

  async writeFile(filePath, content) {
    this.createdFiles.set(filePath, content);
  }

  async createDirectory(dirPath) {
    this.createdDirectories.add(dirPath);
  }

  reset() {
    this.createdFiles.clear();
    this.createdDirectories.clear();
  }
}

describe('Project Scaffolding Integration', () => {
  let mockFileSystemManager;
  let planProjectHandler;
  let approveProjectHandler;
  let getProjectTemplateHandler;

  beforeEach(() => {
    mockFileSystemManager = new MockFileSystemManager();
    planProjectHandler = createPlanProjectHandler();
    approveProjectHandler = createApproveProjectHandler(mockFileSystemManager);
    getProjectTemplateHandler = createGetProjectTemplateHandler();
  });

  describe('Complete Project Creation Workflow', () => {
    test('should complete full static website creation workflow', async () => {
      const projectName = 'My Awesome Website';
      const template = 'static-website';

      // Step 1: Plan the project
      const planResult = await planProjectHandler({
        template,
        projectName
      });

      expect(planResult.success).toBe(true);
      expect(planResult.plan).toBeDefined();
      expect(planResult.plan.projectName).toBe(projectName);
      expect(planResult.plan.template).toBe(template);
      expect(planResult.files).toBeDefined();
      expect(planResult.files.length).toBeGreaterThan(0);

      // Verify plan structure
      expect(planResult.plan.overview).toBeDefined();
      expect(planResult.plan.structure).toBeDefined();
      expect(planResult.plan.setup).toBeDefined();
      expect(planResult.plan.technical).toBeDefined();

      // Verify file tree is generated
      expect(planResult.plan.structure.fileTree).toBeDefined();
      expect(typeof planResult.plan.structure.fileTree).toBe('string');

      // Step 2: Approve and create the project
      const approveResult = await approveProjectHandler({
        approved: true,
        files: planResult.files,
        projectName,
        template,
        createInSubdirectory: true
      });

      expect(approveResult.success).toBe(true);
      expect(approveResult.action).toBe('created');
      expect(approveResult.filesCreated).toBe(planResult.files.length);
      expect(approveResult.projectDirectory).toBeDefined();

      // Verify files were created
      expect(mockFileSystemManager.createdFiles.size).toBe(planResult.files.length);

      // Verify project structure
      const projectDir = projectName.toLowerCase().replace(/[^a-z0-9-]/g, '-');
      expect(mockFileSystemManager.createdFiles.has(`${projectDir}/index.html`)).toBe(true);
      expect(mockFileSystemManager.createdFiles.has(`${projectDir}/css/style.css`)).toBe(true);
      expect(mockFileSystemManager.createdFiles.has(`${projectDir}/js/main.js`)).toBe(true);
      expect(mockFileSystemManager.createdFiles.has(`${projectDir}/README.md`)).toBe(true);

      // Verify content contains project name
      const indexContent = mockFileSystemManager.createdFiles.get(`${projectDir}/index.html`);
      expect(indexContent).toContain(projectName);
    });

    test('should handle project creation cancellation', async () => {
      const projectName = 'Cancelled Project';
      const template = 'react-app';

      // Plan the project
      const planResult = await planProjectHandler({
        template,
        projectName
      });

      expect(planResult.success).toBe(true);

      // Cancel the project creation
      const approveResult = await approveProjectHandler({
        approved: false,
        files: planResult.files,
        projectName,
        template
      });

      expect(approveResult.success).toBe(false);
      expect(approveResult.action).toBe('cancelled');
      expect(approveResult.message).toContain('cancelled');

      // Verify no files were created
      expect(mockFileSystemManager.createdFiles.size).toBe(0);
    });

    test('should create project in current directory when requested', async () => {
      const projectName = 'Current Dir Project';
      const template = 'express-api';

      // Plan the project
      const planResult = await planProjectHandler({
        template,
        projectName
      });

      // Create in current directory
      const approveResult = await approveProjectHandler({
        approved: true,
        files: planResult.files,
        projectName,
        template,
        createInSubdirectory: false
      });

      expect(approveResult.success).toBe(true);
      expect(approveResult.projectDirectory).toBe('.');

      // Verify files are created in root
      expect(mockFileSystemManager.createdFiles.has('package.json')).toBe(true);
      expect(mockFileSystemManager.createdFiles.has('server.js')).toBe(true);
    });
  });

  describe('Project Planning', () => {
    test('should generate comprehensive project plan', async () => {
      const planResult = await planProjectHandler({
        template: 'full-stack',
        projectName: 'Full Stack App'
      });

      expect(planResult.success).toBe(true);
      
      const plan = planResult.plan;
      
      // Check overview
      expect(plan.overview.totalFiles).toBeGreaterThan(10);
      expect(plan.overview.totalSize).toBeDefined();
      expect(plan.overview.estimatedSetupTime).toBeDefined();

      // Check structure
      expect(plan.structure.fileTree).toContain('client/');
      expect(plan.structure.fileTree).toContain('server/');
      expect(plan.structure.fileTypes).toBeDefined();

      // Check setup instructions
      expect(plan.setup.instructions.length).toBeGreaterThan(0);
      expect(plan.setup.requirements.length).toBeGreaterThan(0);
      expect(plan.setup.nextSteps.length).toBeGreaterThan(0);

      // Check technical details
      expect(plan.technical.fileCount).toBe(plan.overview.totalFiles);
      expect(plan.technical.directories.length).toBeGreaterThan(0);
    });

    test('should generate warnings for large projects', async () => {
      // This would test with a template that generates many files
      const planResult = await planProjectHandler({
        template: 'django-app',
        projectName: 'Large Django Project'
      });

      expect(planResult.success).toBe(true);
      
      // Check if warnings are generated appropriately
      if (planResult.warnings && planResult.warnings.length > 0) {
        expect(Array.isArray(planResult.warnings)).toBe(true);
      }
    });

    test('should handle invalid template in planning', async () => {
      const planResult = await planProjectHandler({
        template: 'non-existent-template',
        projectName: 'Invalid Project'
      });

      expect(planResult.success).toBe(false);
      expect(planResult.error).toBeDefined();
    });
  });

  describe('Template Integration', () => {
    test('should work with get_project_template tool', async () => {
      // Get template first
      const templateResult = await getProjectTemplateHandler({
        template: 'vue-app',
        projectName: 'Vue Test App'
      });

      expect(templateResult.success).toBe(true);

      // Plan using the same parameters
      const planResult = await planProjectHandler({
        template: 'vue-app',
        projectName: 'Vue Test App'
      });

      expect(planResult.success).toBe(true);
      expect(planResult.files.length).toBe(templateResult.fileCount);

      // Files should be equivalent
      expect(planResult.files.length).toBe(templateResult.files.length);
    });
  });

  describe('Error Handling', () => {
    test('should handle missing files in approval', async () => {
      const approveResult = await approveProjectHandler({
        approved: true,
        files: [],
        projectName: 'Empty Project',
        template: 'static-website'
      });

      expect(approveResult.success).toBe(false);
      expect(approveResult.action).toBe('failed');
    });

    test('should handle missing required parameters', async () => {
      await expect(
        planProjectHandler({})
      ).rejects.toThrow('Template parameter is required');
    });

    test('should handle file creation errors gracefully', async () => {
      // Mock file system to fail
      const failingFileSystemManager = {
        async writeFile() {
          throw new Error('Disk full');
        },
        async createDirectory() {
          throw new Error('Permission denied');
        }
      };

      const failingApproveHandler = createApproveProjectHandler(failingFileSystemManager);

      const planResult = await planProjectHandler({
        template: 'static-website',
        projectName: 'Failing Project'
      });

      const approveResult = await failingApproveHandler({
        approved: true,
        files: planResult.files,
        projectName: 'Failing Project',
        template: 'static-website'
      });

      expect(approveResult.success).toBe(false);
      expect(approveResult.action).toBe('failed');
      expect(approveResult.message).toContain('failed');
    });
  });

  describe('File Tree Generation', () => {
    test('should generate proper ASCII file tree', async () => {
      const planResult = await planProjectHandler({
        template: 'react-app',
        projectName: 'Tree Test'
      });

      const fileTree = planResult.plan.structure.fileTree;
      
      // Should contain proper tree characters
      expect(fileTree).toContain('├──');
      expect(fileTree).toContain('└──');
      
      // Should show directories with /
      expect(fileTree).toContain('src/');
      
      // Should show file sizes
      expect(fileTree).toMatch(/\(\d+[BK]+\)/);
    });
  });

  describe('Setup Instructions', () => {
    test('should generate appropriate setup instructions for each template', async () => {
      const templates = ['static-website', 'react-app', 'express-api', 'flask-api'];
      
      for (const template of templates) {
        const planResult = await planProjectHandler({
          template,
          projectName: `Test ${template}`
        });

        expect(planResult.success).toBe(true);
        expect(planResult.plan.setup.instructions.length).toBeGreaterThan(0);
        
        // Check template-specific instructions
        const instructions = planResult.plan.setup.instructions;
        
        switch (template) {
          case 'static-website':
            expect(instructions.some(i => i.includes('index.html'))).toBe(true);
            break;
          case 'react-app':
            expect(instructions.some(i => i.includes('npm install'))).toBe(true);
            break;
          case 'express-api':
            expect(instructions.some(i => i.includes('npm install'))).toBe(true);
            break;
          case 'flask-api':
            expect(instructions.some(i => i.includes('pip install'))).toBe(true);
            break;
        }
      }
    });
  });
});